const company = items.find(i => i.contact_person); // Garante que é a empresa pelo contato

// 2. Filtra APENAS os participantes reais
// Removemos objetos que tenham 'message_template', 'title' (evento) ou 'contact_person' (empresa)
// Mesmo que a empresa tenha telefone, ela não cairá aqui.
