function normalizePhone(phone) {
  if (!phone) return null;
  // Remove tudo que não é dígito
  let digits = phone.replace(/\D/g, '');

  // Tratamento básico para BR (se tiver 10 ou 11 dígitos e não começar com 55, adiciona)
  if (digits.length >= 10 && digits.length <= 11) {
    digits = '55' + digits;
  }

  return digits;
}

function normalizeText(text) {
  if (!text) return '';
  return text
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '');
}

function formatDate(isoDate) {
  if (!isoDate) return '';
  // Ajuste o timezone se necessário, aqui usa o do servidor/n8n
  return new Date(isoDate).toLocaleDateString('pt-BR');
}

function formatTime(isoDate) {
  if (!isoDate) return '';
  return new Date(isoDate).toLocaleTimeString('pt-BR', {
    hour: '2-digit',
    minute: '2-digit'
  });
}

function parseLocation(event) {
  if (!event?.location) return {};
  try {
    return typeof event.location === 'string'
      ? JSON.parse(event.location)
      : event.location;
  } catch {
    return {};
  }
}

function getCountry(event) {
  const loc = parseLocation(event);
  return loc.country || '';
}

function getCities(event) {
  const loc = parseLocation(event);
  if (Array.isArray(loc.cities) && loc.cities.length > 0) {
    return loc.cities.join(', ');
  }
  return '';
}

function getLocation(event) {
  const loc = parseLocation(event);
  if (loc.cities?.length) return loc.cities.join(', ');
  if (loc.country) return loc.country;
  return '';
}

function resolveVariable(variableName, participant, event, example, company) {
  const originalName = variableName;
  const name = normalizeText(variableName);

  // 1. PRIORIDADE MÁXIMA: DADOS ESPECÍFICOS DO PARTICIPANTE (Custom Data)
  // Isso garante que "data_nascimento" do cliente não seja substituída pela data do evento.
  if (participant.custom_data) {
    // Busca exata pela chave original
    if (participant.custom_data[originalName]) return participant.custom_data[originalName];
    // Busca normalizada
    const customKey = Object.keys(participant.custom_data).find(k => normalizeText(k) === name);
    if (customKey) return participant.custom_data[customKey];
  }

  // 2. MAPEAMENTO EXPLÍCITO (Evita erros de "includes")
  const systemMap = {
    // Evento
    'evento': event?.title,
    'nome_evento': event?.title,
    'titulo': event?.title,
    'data_evento': formatDate(event?.event_date),
    'data': formatDate(event?.event_date),
    'hora_evento': formatTime(event?.event_date),
    'local': getLocation(event),
    'endereco': getLocation(event),

    // Evento - Fim (NOVO)
    'data_final': formatDate(event?.end_date),
    'data_fim': formatDate(event?.end_date),
    'termino': formatDate(event?.end_date),
    'encerramento': formatDate(event?.end_date),
    'hora_final': formatTime(event?.end_date),
    'hora_fim': formatTime(event?.end_date),

    // Participante (Campos Nativos)
    'nome': participant.name,
    'nome_participante': participant.name,
    'email': participant.email,
    'telefone': participant.phone,

    // Empresa
    'empresa': company?.name,
    'nome_empresa': company?.name,
    'cliente': company?.name
  };

  if (systemMap[name]) return systemMap[name];

  // 2.1 LOCALIZAÇÃO EXPLÍCITA (ANTES DA HEURÍSTICA)
  if (name === 'pais' || name === 'country') {
    return getCountry(event) || example || '';
  }

  if (name === 'cidade' || name === 'city' || name === 'cidades') {
    return getCities(event) || example || '';
  }


  // 3. BUSCA SEMÂNTICA SEGURA (Heurística Avançada)
  // Só entra aqui se não achou correspondência exata no passo 1 ou 2.

