  if (
    name.includes('fim') || 
    name.includes('final') || 
    name.includes('termin') || // termino, termina
    name.includes('encerr') || // encerramento
    name.includes('ate')       // ex: "de_x_ate_y"
  ) {
      if (name.includes('hora') || name.includes('horario')) {
          return formatTime(event?.end_date);
      }
      return formatDate(event?.end_date);
  }

  // --- GRUPO A: DATAS E HORÁRIOS ---
  // Captura: "data", "dia", "data_inicio", "quando"
  // Segurança: Ignora se tiver "nascimento" ou "vencimento" (provavelmente é do cliente)
  if (
    (name.includes('data') || name.includes('dia') || name.includes('quando')) &&
    !name.includes('nascimento') && 
    !name.includes('vencimento')
  ) {
      return formatDate(event?.event_date);
  }

  // Captura: "hora", "horario", "inicio", "hora_chegada"
  if (name.includes('hora') || name.includes('inicio')) {
      return formatTime(event?.event_date);
  }

  // --- GRUPO B: LOCALIZAÇÃO (Evento) ---
  // Captura: "local", "local_do_evento", "evento_local", "endereco", "onde", "cidade", "mapa"
  // Funciona para "local" no começo, meio ou fim da string.
  if (
    name.includes('local') || 
    name.includes('endereco') || 
    name.includes('lugar') || 
    name.includes('onde') || 
    name.includes('cidade') ||
    name.includes('mapa')
  ) {
      return getLocation(event);
  }

  // --- GRUPO C: IDENTIFICAÇÃO DO EVENTO ---
  // IMPORTANTE: Checar isso ANTES de "nome" genérico.
  // Captura: "nome_do_evento", "titulo_evento", "workshop", "curso", "webinar", "palestra"
  if (
    name.includes('evento') || 
    name.includes('titulo') || 
    name.includes('workshop') || 
    name.includes('curso') || 
    name.includes('palestra') ||
    name.includes('webinar')
  ) {
      return event?.title;
  }

  // --- GRUPO D: EMPRESA ---
  // Captura: "nome_empresa", "empresa_responsavel", "organizacao"
  if (name.includes('empresa') || name.includes('organizacao') || name.includes('cliente')) {
      return company?.name;
  }

  // --- GRUPO E: IDENTIFICAÇÃO DO PARTICIPANTE (Genérico) ---
  // Este é o "balde" final. Se tiver "nome", assumimos que é a pessoa.
  // Captura: "nome", "nome_completo", "primeiro_nome", "cliente", "participante", "aluno", "visitante"
  if (
    name.includes('nome') || 
    name.includes('participante') || 
    name.includes('aluno') ||
    name.includes('visitante') ||
    name.includes('funcionário') ||
    name.includes('funcionario') ||
    name === 'user' // As vezes vem user
  ) {
      return participant.name;
  }

  // Captura variações de contato
  if (name.includes('mail')) return participant.email; // email, e-mail, mail
  if (name.includes('fone') || name.includes('celular') || name.includes('zap')) return participant.phone;

  // 4. FALLBACK (Mantido)
  return example ?? '';
}

// --- Montagem Final ---

return participants.map(participant => {
  // Resolve os parâmetros usando a lógica robusta
  const parameters = template.variables.map(v =>
    resolveVariable(v.name, participant, event, v.example, company)
  );

  return {
    json: {
      participant_id: participant.id,
      event_id: participant.event_id, // Campo solicitado

